SELECT count(*) FROM aka_name, name, cast_info, title, movie_keyword, kind_type, role_type WHERE aka_name.person_id = name.id AND cast_info.person_id = name.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.role_id = role_type.id;